import React, { createContext, useContext, useState, useCallback } from 'react';
import { WORK_ORDERS, NOTIFICATIONS } from '../data/mockData';

const AppContext = createContext(null);

export function AppProvider({ children }) {
  const [role, setRole]             = useState('client');
  const [workOrders, setWorkOrders] = useState(WORK_ORDERS);
  const [notifications, setNotifications] = useState(NOTIFICATIONS);
  const [toasts, setToasts]         = useState([]);

  // ── Toast ────────────────────────────────────────────────
  const showToast = useCallback((message, type = 'default') => {
    const id = Date.now();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
  }, []);

  // ── Work Order mutations ─────────────────────────────────
  const updateWOStatus = useCallback((id, newStatus, activityEntry) => {
    setWorkOrders(prev => prev.map(wo => {
      if (wo.id !== id) return wo;
      const updated = { ...wo, status: newStatus };
      if (activityEntry) {
        updated.activity = [...wo.activity, {
          id: `a${Date.now()}`,
          time: new Date().toLocaleString('en-IN', { day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit' }),
          ...activityEntry,
        }];
      }
      return updated;
    }));
  }, []);

  const createWorkOrder = useCallback((data) => {
    const newWO = {
      id: `WO-${2400 + workOrders.length + 1}`,
      status: 'open',
      raisedOn: new Date().toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' }),
      elapsedHours: 0,
      activity: [{
        id: 'a1',
        time: new Date().toLocaleString('en-IN', { day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit' }),
        by: 'Client (Admin)',
        action: 'Work order created',
        note: '',
        type: 'default',
      }],
      ...data,
    };
    setWorkOrders(prev => [newWO, ...prev]);
    return newWO.id;
  }, [workOrders.length]);

  const markNotifRead = useCallback((id) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n));
  }, []);

  const unreadCount = notifications.filter(n => !n.read).length;

  return (
    <AppContext.Provider value={{
      role, setRole,
      workOrders, updateWOStatus, createWorkOrder,
      notifications, markNotifRead, unreadCount,
      toasts, showToast,
    }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const ctx = useContext(AppContext);
  if (!ctx) throw new Error('useApp must be used inside AppProvider');
  return ctx;
}
